<template>
	<view id="app">
		<!-- 全局样式 -->
	</view>
</template>

<script>
	import { useUserStore } from '@/store/user'
	
	export default {
		onLaunch: function() {
			// 微信登录 + 角色验证
			this.checkLogin()
		},
		onShow: function() {
			// App显示
		},
		onHide: function() {
			// App隐藏
		},
		methods: {
			async checkLogin() {
				try {
					const userStore = useUserStore()
					
					// 如果用户手动退出，跳过静默登录
					if (userStore.manuallyLoggedOut) {
						console.log('用户手动退出，跳过静默登录')
						return
					}
					
					// 微信登录
					const loginRes = await uni.login({
						provider: 'weixin'
					})
					
					if (loginRes.code) {
						// 调用云函数获取用户信息
						const res = await uniCloud.callFunction({
							name: 'login',
							data: {
								code: loginRes.code
							}
						})
						
						if (res.result.success) {
							// 保存用户信息到store
							userStore.setUser(res.result.userInfo)
							
							// 保存openid到本地
							uni.setStorageSync('openid', res.result.userInfo.openid)
							
							// 跳转到首页
							uni.switchTab({
								url: '/pages/index/index'
							})
						}
					}
				} catch (e) {
					console.error('静默登录失败', e)
				}
			}
		}
	}
</script>

